srcDoc.css:
.title-container {
  position: relative;
  text-align: center;
  margin-top: -5px;
}

.line-container {
  position: relative;
  display: inline-block;
  margin-top: 10px;
  margin-bottom: 10px;
}

.background-bar {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, 10%);
  width: 100%;
  height: 1em;
  background-color: #E1F9B7;
  z-index: 0;
  border-radius: 4px;
}

.styled-title {
  font-family: "Poppins", sans-serif;
  font-size: 28px;
  font-weight: bold;
  color: #2C3034;
  position: relative;
  z-index: 1;
  margin: 0;
}

srcDoc.js:
const SUBCATEGORY_MAP = {
  gaz: "Gaz",
  electricite: "Électricité",
  electricite_et_gaz: "Électricité et gaz"
};
function renderPage() {
  const title = document.querySelector(".styled-title");
  title.textContent = `pour votre contrat ${SUBCATEGORY_MAP[appsmith.model.subcategory]}`;
}
appsmith.onReady(() => {
  if (Object.keys(appsmith.model).length > 0) {
    renderPage();
  }
});
appsmith.onModelChange(newModel => {
  if (Object.keys(newModel).length > 0) {
    renderPage();
  }
});

